#include <stdio.h>
#include <stdlib.h>

// Define the structure for a linked list node
typedef struct Node {
    int data;
    struct Node* next;
} Node;

// Function to create a new node
Node* createNode(int data) {
    Node* newNode = (Node*) malloc(sizeof(Node));
    if (!newNode) {
        printf("Memory error\n");
        return NULL;
    }
    newNode->data = data;
    newNode->next = NULL;
    return newNode;
}

// Function to insert a node at the end of the linked list
void insertNode(Node** head, int data) {
    Node* newNode = createNode(data);
    if (*head == NULL) {
        *head = newNode;
    } else {
        Node* lastNode = *head;
        while (lastNode->next) {
            lastNode = lastNode->next;
        }
        lastNode->next = newNode;
    }
}

// Function to remove nodes with a given key from the linked list
Node* removeKey(Node* head, int key) {
    // Remove nodes from the beginning
    while (head != NULL && head->data == key) {
        Node* temp = head;
        head = head->next;
        free(temp);
    }

    if (head == NULL) return NULL;

    Node* curr = head;

    // Remove nodes equal to key
    while (curr->next != NULL) {
        if (curr->next->data == key) {
            Node* temp = curr->next;
            curr->next = curr->next->next;
            free(temp);
        } else {
            curr = curr->next;
        }
    }

    return head;
}

// Function to print the linked list
void printList(Node* head) {
    while (head) {
        printf("%d ", head->data);
        head = head->next;
    }
    printf("\n");
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int n;
        scanf("%d", &n);
        Node* head = NULL;
        for (int i = 0; i < n; i++) {
            int data;
            scanf("%d", &data);
            insertNode(&head, data);
        }
        int key;
        scanf("%d", &key);
        head = removeKey(head, key);
        if (head == NULL) {
            printf("-1\n");
        } else {
            printList(head);
        }
    }
    return 0;
}

