import java.util.Scanner;
public class Main {
    // Define the structure for a linked list node
    static class Node {
        int data;
        Node next;
        Node(int data) {
            this.data = data;
            this.next = null;
        }
    }

    // Function to create a new node
    static Node createNode(int data) {
        return new Node(data);
    }

    // Function to insert a node at the end of the linked list
    static void insertNode(Node head, int data, Node[] list) {
        Node newNode = createNode(data);
        if (head == null) {
            list[0] = newNode;
        } else {
            Node lastNode = head;
            while (lastNode.next != null) {
                lastNode = lastNode.next;
            }
            lastNode.next = newNode;
        }
    }

    // Function to remove nodes with a given key from the linked list
    static Node removeKey(Node head, int key) {
        // Remove nodes from the beginning
        while (head != null && head.data == key) {
            Node temp = head;
            head = head.next;
            temp = null;
        }

        if (head == null) return null;

        Node curr = head;

        // Remove nodes equal to key
        while (curr.next != null) {
            if (curr.next.data == key) {
                Node temp = curr.next;
                curr.next = curr.next.next;
                temp = null;
            } else {
                curr = curr.next;
            }
        }

        return head;
    }

    // Function to print the linked list
    static void printList(Node head) {
        while (head != null) {
            System.out.print(head.data + " ");
            head = head.next;
        }
        System.out.println();
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int n = sc.nextInt();
            Node head = null;
            Node[] list = new Node[1];
            for (int i = 0; i < n; i++) {
                int data = sc.nextInt();
                insertNode(head, data, list);
                head = list[0];
            }
            int key = sc.nextInt();
            head = removeKey(head, key);
            if (head == null) {
                System.out.println(-1);
            } else {
                printList(head);
            }
        }
    }
}

